import type { TimeFilters } from '../types'
import { createTimePeriodFromFilters } from '../utils'
import { AnalysesName } from './constants'
import type {
  AnalysisInput,
  AnalysisRequest,
  PwcInput,
  PwcRequest,
  SolarModelInput,
  SolarModelRequest,
  SolarRadiationInput,
  SolarRadiationRequest,
  SvfModelRequest,
  UtciModelInput,
  UtciModelRequest,
  TCSModelInput,
  TCSModelRequest,
} from './schemas'
import type { WeatherDataPoint } from './weather-data'
import { filterEPWData, isEPWData } from './weather-filter'

// ---------------------------------------------------------------------------
// camelCase -> snake_case helper (matching Python SDK's _camel_to_snake)
// ---------------------------------------------------------------------------

/**
 * Convert a camelCase string to snake_case.
 * Splits on uppercase boundaries: 'diffuseHorizontalRadiation'
 * becomes 'diffuse_horizontal_radiation'.
 */
function camelToSnake(name: string): string {
  const chars: string[] = []
  for (const ch of name) {
    if (ch >= 'A' && ch <= 'Z' && chars.length > 0) {
      chars.push('_')
    }
    chars.push(ch.toLowerCase())
  }
  return chars.join('')
}

// ---------------------------------------------------------------------------
// extractWeatherFields -- ported from Python SDK utils.py
// ---------------------------------------------------------------------------

/**
 * Extract specified fields from weather data points into flat lists.
 *
 * Matches Python SDK's `extract_weather_fields()` behaviour:
 * - Takes a list of WeatherDataPoint instances and a list of camelCase field names
 * - Returns a dict mapping **snake_case** keys to lists of float values
 * - Null/undefined values are skipped
 *
 * Note: Returns snake_case keys (e.g. `diffuse_horizontal_radiation`) to match the
 * Python SDK's `_camel_to_snake()` convention. The SDK's `serializeToKebab()` handles
 * the final camelCase/snake_case -> kebab-case conversion at the HTTP serialization layer.
 *
 * @param weatherData - List of WeatherDataPoint instances
 * @param fields - camelCase attribute names from WeatherDataPoint
 *   (e.g. `["diffuseHorizontalRadiation", "directNormalRadiation"]`)
 * @returns Record mapping snake_case keys to arrays of numbers. Null values are skipped.
 */
export function extractWeatherFields(
  weatherData: WeatherDataPoint[],
  fields: readonly string[],
): Record<string, number[]> {
  const result: Record<string, number[]> = {}
  for (const f of fields) {
    result[camelToSnake(f)] = []
  }
  for (const point of weatherData) {
    for (const field of fields) {
      const value = (point as Record<string, unknown>)[field]
      if (value !== null && value !== undefined) {
        result[camelToSnake(field)].push(Number(value))
      }
    }
  }
  return result
}

// ---------------------------------------------------------------------------
// Weather data extraction helpers (internal, used by transformAnalysisInput)
// ---------------------------------------------------------------------------

/**
 * Extract thermal weather data arrays from weather data points
 */
function extractThermalWeatherData(weatherData: WeatherDataPoint[]) {
  const accum: Record<string, number[]> = {
    horizontalInfraredRadiationIntensity: [],
    diffuseHorizontalRadiation: [],
    directNormalRadiation: [],
    globalHorizontalRadiation: [],
    dryBulbTemperature: [],
    windSpeed: [],
    relativeHumidity: [],
  }

  for (const point of weatherData) {
    if (
      point.horizontalInfraredRadiationIntensity !== null &&
      point.horizontalInfraredRadiationIntensity !== undefined
    ) {
      accum.horizontalInfraredRadiationIntensity.push(point.horizontalInfraredRadiationIntensity)
    }
    if (
      point.diffuseHorizontalRadiation !== null &&
      point.diffuseHorizontalRadiation !== undefined
    ) {
      accum.diffuseHorizontalRadiation.push(point.diffuseHorizontalRadiation)
    }
    if (point.directNormalRadiation !== null && point.directNormalRadiation !== undefined) {
      accum.directNormalRadiation.push(point.directNormalRadiation)
    }
    if (point.globalHorizontalRadiation !== null && point.globalHorizontalRadiation !== undefined) {
      accum.globalHorizontalRadiation.push(point.globalHorizontalRadiation)
    }
    if (point.dryBulbTemperature !== null && point.dryBulbTemperature !== undefined) {
      accum.dryBulbTemperature.push(point.dryBulbTemperature)
    }
    if (point.windSpeed !== null && point.windSpeed !== undefined) {
      accum.windSpeed.push(point.windSpeed)
    }
    if (point.relativeHumidity !== null && point.relativeHumidity !== undefined) {
      accum.relativeHumidity.push(point.relativeHumidity)
    }
  }

  return accum
}

/**
 * Extract wind data arrays from weather data points
 */
function extractWindData(weatherData: WeatherDataPoint[]) {
  const windSpeed: number[] = []
  const windDirection: number[] = []

  for (const point of weatherData) {
    if (
      point.windSpeed !== null &&
      point.windSpeed !== undefined &&
      point.windDirection !== null &&
      point.windDirection !== undefined
    ) {
      windSpeed.push(point.windSpeed)
      windDirection.push(point.windDirection)
    }
  }

  return { windSpeed, windDirection }
}

/**
 * Extract solar radiation data arrays from weather data points
 */
function extractSolarRadiationData(weatherData: WeatherDataPoint[]) {
  const directNormalRadiation: number[] = []
  const diffuseHorizontalRadiation: number[] = []

  for (const point of weatherData) {
    if (point.directNormalRadiation !== null && point.directNormalRadiation !== undefined) {
      directNormalRadiation.push(point.directNormalRadiation)
    }
    if (
      point.diffuseHorizontalRadiation !== null &&
      point.diffuseHorizontalRadiation !== undefined
    ) {
      diffuseHorizontalRadiation.push(point.diffuseHorizontalRadiation)
    }
  }

  return { directNormalRadiation, diffuseHorizontalRadiation }
}

/**
 * Normalize weather data to WeatherDataPoint[] format
 * If input is EPWData, filter it using the provided dateFilters
 * If input is already WeatherDataPoint[], return as-is
 */
function normalizeWeatherData(weatherData: unknown, dateFilters: TimeFilters): WeatherDataPoint[] {
  if (isEPWData(weatherData)) {
    return filterEPWData(weatherData, dateFilters)
  }
  return weatherData as WeatherDataPoint[]
}

/**
 * Transform AnalysisInput (with dateFilters) to AnalysisRequest (with TimeStamps).
 *
 * Converts user-friendly input format (using `dateFilters`) into the API-ready
 * request format (using `TimeStamps`). Automatically filters EPWData to
 * WeatherDataPoint[] if full EPW data is provided.
 *
 * @param input - The analysis input with dateFilters and optional EPW weather data.
 * @returns The API-ready analysis request with TimeStamps and extracted weather arrays.
 *
 * @example
 * ```ts
 * const request = transformAnalysisInput({
 *   analysisType: AnalysesName.DirectSunHours,
 *   geometries: {},
 *   latitude: 52.52,
 *   longitude: 13.405,
 *   dateFilters: {
 *     period: { start: { month: 6, day: 1, hour: 8 }, end: { month: 9, day: 30, hour: 18 } },
 *   },
 * })
 * ```
 */
export function transformAnalysisInput(input: AnalysisInput): AnalysisRequest {
  // Handle WindModelRequest (no dateFilters)
  if (input.analysisType === AnalysesName.WindSpeed) {
    return input as AnalysisRequest
  }

  // Handle SvfModelRequest (geometry-only, no dateFilters/location/weather)
  if (input.analysisType === AnalysesName.SkyViewFactors) {
    return input as SvfModelRequest
  }

  // All other inputs have dateFilters
  if ('dateFilters' in input) {
    const timeFilters: TimeFilters = input.dateFilters
    const timePeriod = createTimePeriodFromFilters(timeFilters)

    // Solar Model (DirectSunHours, DaylightAvailability)
    if (
      input.analysisType === AnalysesName.DirectSunHours ||
      input.analysisType === AnalysesName.DaylightAvailability
    ) {
      const solarInput = input as SolarModelInput
      const solarRequest: SolarModelRequest = {
        analysisType: solarInput.analysisType,
        geometries: solarInput.geometries,
        vegetation: solarInput.vegetation,
        groundMaterials: solarInput.groundMaterials,
        latitude: solarInput.latitude,
        longitude: solarInput.longitude,
        timePeriod,
      }
      return solarRequest
    }

    // TCI Model
    if (input.analysisType === AnalysesName.ThermalComfortIndex) {
      const tciInput = input as UtciModelInput
      const normalizedWeatherData = normalizeWeatherData(tciInput.weatherData, timeFilters)
      const weatherArrays = extractThermalWeatherData(normalizedWeatherData)
      const tciRequest: UtciModelRequest = {
        analysisType: tciInput.analysisType,
        geometries: tciInput.geometries,
        vegetation: tciInput.vegetation,
        groundMaterials: tciInput.groundMaterials,
        latitude: tciInput.latitude,
        longitude: tciInput.longitude,
        timePeriod,
        horizontalInfraredRadiationIntensity: weatherArrays.horizontalInfraredRadiationIntensity,
        diffuseHorizontalRadiation: weatherArrays.diffuseHorizontalRadiation,
        directNormalRadiation: weatherArrays.directNormalRadiation,
        globalHorizontalRadiation: weatherArrays.globalHorizontalRadiation,
        dryBulbTemperature: weatherArrays.dryBulbTemperature,
        windSpeed: weatherArrays.windSpeed,
        relativeHumidity: weatherArrays.relativeHumidity,
      }
      return tciRequest
    }
    if (input.analysisType === AnalysesName.ThermalComfortStatistics) {
      const tcsInput = input as TCSModelInput
      const normalizedWeatherData = normalizeWeatherData(tcsInput.weatherData, timeFilters)
      const weatherArrays = extractThermalWeatherData(normalizedWeatherData)
      const tcsRequest: TCSModelRequest = {
        analysisType: tcsInput.analysisType,
        geometries: tcsInput.geometries,
        vegetation: tcsInput.vegetation,
        subtype: tcsInput.subtype,
        groundMaterials: tcsInput.groundMaterials,
        latitude: tcsInput.latitude,
        longitude: tcsInput.longitude,
        timePeriod,
        horizontalInfraredRadiationIntensity: weatherArrays.horizontalInfraredRadiationIntensity,
        diffuseHorizontalRadiation: weatherArrays.diffuseHorizontalRadiation,
        directNormalRadiation: weatherArrays.directNormalRadiation,
        globalHorizontalRadiation: weatherArrays.globalHorizontalRadiation,
        dryBulbTemperature: weatherArrays.dryBulbTemperature,
        windSpeed: weatherArrays.windSpeed,
        relativeHumidity: weatherArrays.relativeHumidity,
      }
      return tcsRequest
    }

    // PWC Model — wind arrays go at TOP LEVEL, matching Python SDK's
    // PwcModelRequest (server expects `wind-speed` + `wind-direction`,
    // not nested `wind-data`).
    if (input.analysisType === AnalysesName.PedestrianWindComfort) {
      const pwcInput = input as PwcInput
      const normalizedWeatherData = normalizeWeatherData(pwcInput.weatherData, timeFilters)
      const windData = extractWindData(normalizedWeatherData)
      const pwcRequest: PwcRequest = {
        analysisType: pwcInput.analysisType,
        criteria: pwcInput.criteria,
        geometries: pwcInput.geometries,
        vegetation: pwcInput.vegetation,
        groundMaterials: pwcInput.groundMaterials,
        windSpeed: windData.windSpeed,
        windDirection: windData.windDirection,
      }
      return pwcRequest
    }

    // Solar Radiation Model
    if (input.analysisType === AnalysesName.SolarRadiation) {
      const solarRadInput = input as SolarRadiationInput
      const normalizedWeatherData = normalizeWeatherData(solarRadInput.weatherData, timeFilters)
      const radiationData = extractSolarRadiationData(normalizedWeatherData)
      const solarRadRequest: SolarRadiationRequest = {
        analysisType: solarRadInput.analysisType,
        geometries: solarRadInput.geometries,
        vegetation: solarRadInput.vegetation,
        groundMaterials: solarRadInput.groundMaterials,
        latitude: solarRadInput.latitude,
        longitude: solarRadInput.longitude,
        timePeriod,
        directNormalRadiation: radiationData.directNormalRadiation,
        diffuseHorizontalRadiation: radiationData.diffuseHorizontalRadiation,
      }
      return solarRadRequest
    }
  }

  // This should never be reached as all analysis types are handled above
  throw new Error(`Unsupported analysis type: ${(input as any).analysisType}`)
}
