import type { IJobsService, Job } from '../jobs/types'
import type { Logger } from '../logger'
import { deserializeToCamelCase, serializeToKebab } from '../utils'
import { transformAnalysisInput } from './factories'
import type { AnalysisInput } from './schemas'

export interface AnalysisServiceConfig {
  logger: Logger
  /** Pre-configured jobs service for async execution. */
  jobsService?: IJobsService
}

/**
 * Interface for dependency injection and testing.
 */
export interface IAnalysisService {
  execute(
    input: AnalysisInput,
    opts?: { webhookUrl?: string; webhookEvents?: string[] },
  ): Promise<Job>
}

/**
 * Analysis service client for running environmental analysis models.
 *
 * Async-only execution: all analyses are submitted as async jobs via
 * JobsService. The `execute` method submits the job and returns a Job
 * handle. Consumers use `JobsService.waitForCompletion` and
 * `JobsService.downloadResults` to poll and retrieve results.
 */
export class AnalysisService implements IAnalysisService {
  private readonly logger: Logger
  private readonly jobsService: IJobsService | undefined

  constructor(config: AnalysisServiceConfig) {
    this.logger = config.logger
    this.jobsService = config.jobsService
  }

  /**
   * Submit an analysis for async execution.
   *
   * Transforms the input (dateFilters -> TimeStamps, weather data filtering),
   * serializes to kebab-case for the API, and delegates to JobsService.submit.
   *
   * @param input - Analysis input configuration
   * @param opts - Optional webhook configuration
   * @returns Job handle for tracking execution
   *
   * @throws Error if no jobsService was provided
   */
  async execute(
    input: AnalysisInput,
    opts?: { webhookUrl?: string; webhookEvents?: string[] },
  ): Promise<Job> {
    if (!this.jobsService) {
      throw new Error(
        'Cannot execute: no jobsService was provided. ' +
          'Pass an IJobsService instance when constructing AnalysisService.',
      )
    }

    const payload = transformAnalysisInput(input)
    const analysisType = payload.analysisType

    this.logger.debug(`Async model execution: ${analysisType}`)

    // Serialize to kebab-case for the API
    const serialized = serializeToKebab(payload) as Record<string, unknown>

    // Preserve camelCase for wind-data as backend expects it
    if (serialized['wind-data']) {
      serialized['wind-data'] = deserializeToCamelCase(serialized['wind-data'])
    }

    return this.jobsService.submit(analysisType, serialized, opts)
  }
}
